import os
import difflib
import shutil

def compare_metadata(org1_path, org2_path, output_path):
    if not os.path.exists(output_path):
        os.makedirs(output_path)

    for root, dirs, files in os.walk(org1_path):
        for file in files:
            file1_path = os.path.join(root, file)
            file2_path = os.path.join(org2_path, os.path.relpath(file1_path, org1_path))

            if os.path.exists(file2_path):
                with open(file1_path, 'r') as f1, open(file2_path, 'r') as f2:
                    diff = list(difflib.unified_diff(f1.readlines(), f2.readlines(), 
                                                      fromfile=file1_path, 
                                                      tofile=file2_path))
                    if diff:
                        output_file_path = os.path.join(output_path, os.path.relpath(file1_path, org1_path))
                        output_file_dir = os.path.dirname(output_file_path)
                        if not os.path.exists(output_file_dir):
                            os.makedirs(output_file_dir)
                        with open(output_file_path, 'w') as output_file:
                            output_file.writelines(diff)

def solve(org1_path, org2_path, output_path):
    compare_metadata(org1_path, org2_path, output_path)
